"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[62112],{8088:(e,s,i)=>{i.r(s),i.d(s,{data:()=>a});const a={key:"v-3f99531c",path:"/vue/vue3/guid/vueuse.html",title:"vueuse",lang:"zh-CN",frontmatter:{},excerpt:"",headers:[{level:2,title:"一、特征",slug:"一、特征",children:[]},{level:2,title:"二、安装",slug:"二、安装",children:[]},{level:2,title:"三、使用",slug:"三、使用",children:[{level:3,title:"useVModel",slug:"usevmodel",children:[]}]},{level:2,title:"参考资料",slug:"参考资料",children:[]}],git:{updatedTime:1653451151e3,contributors:[{name:"panzhiyue",email:"30484534+panzhiyue@users.noreply.github.com",commits:1}]},filePathRelative:"vue/vue3/guid/vueuse.md"}},87753:(e,s,i)=>{i.r(s),i.d(s,{default:()=>o});var a=i(57293);const n=(0,a._)("h1",{id:"vueuse",tabindex:"-1"},[(0,a._)("a",{class:"header-anchor",href:"#vueuse","aria-hidden":"true"},"#"),(0,a.Uk)(" vueuse")],-1),d=(0,a.Uk)("VueUse是一个基于 Composition "),t={href:"https://so.csdn.net/so/search?q=API&spm=1001.2101.3001.7020",target:"_blank",rel:"noopener noreferrer"},r=(0,a.Uk)("API"),l=(0,a.Uk)(" 实现的基本 Vue 组合实用函数的集合。"),u=(0,a.uE)('<p>VueUse可能是受到了react-use的启发，可以看做是vue版的hook，Vue Compostion API支持了更好的逻辑分离，让这些常用的工具可以被复用，能够让你快速地构建丰富的应用，大大地提高你的开发效率在，避免自己去封装一些常用的功能函数，比如：防抖，节流，定时器等。</p><p>几天前，一个偶然的机会发现看到Element-plus组件库的源码中已经大量的使用了VueUse，所以可以大胆地在项目中使用了。 官网地址：https://vueuse.org/</p><h2 id="一、特征" tabindex="-1"><a class="header-anchor" href="#一、特征" aria-hidden="true">#</a> 一、特征</h2><p>无缝迁移：同时支持Vue2和Vue3 支持按需引入：只取你想要的 强类型：用 TypeScript 编写，带有 TS Docs 灵活：可配置的事件过滤器 无需打包：支持CDN方式引入使用 功能丰富：截止目前180+功能任你选择 友好的SSR：与服务器端渲染/生成完美配合 互动演示：功能文档还附带互动演示 附加插件：支持Router、Firebase、RxJS等多种插件</p><h2 id="二、安装" tabindex="-1"><a class="header-anchor" href="#二、安装" aria-hidden="true">#</a> 二、安装</h2><p><strong>npm</strong></p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>npm i @vueuse/core\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><strong>yarn</strong></p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>yarn add @vueuse/core\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><strong>CDN引入</strong></p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>&lt;script src=&quot;https://unpkg.com/@vueuse/shared&quot;&gt;&lt;/script&gt;\n&lt;script src=&quot;https://unpkg.com/@vueuse/core&quot;&gt;&lt;/script&gt;\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>作为 window.VueUse 暴露给全局。</p><h2 id="三、使用" tabindex="-1"><a class="header-anchor" href="#三、使用" aria-hidden="true">#</a> 三、使用</h2><h3 id="usevmodel" tabindex="-1"><a class="header-anchor" href="#usevmodel" aria-hidden="true">#</a> useVModel</h3><p>v-model 绑定的简写</p><h4 id="用法" tabindex="-1"><a class="header-anchor" href="#用法" aria-hidden="true">#</a> 用法</h4><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>import { useVModel } from &#39;@vueuse/core&#39;\n\nexport default {\n  setup(props, { emit }) {\n    const data = useVModel(props, &#39;data&#39;, emit)\n\n    console.log(data.value) // props.data\n    data.value = &#39;foo&#39; // emit(&#39;update:data&#39;, &#39;foo&#39;)\n  },\n}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="script-setup" tabindex="-1"><a class="header-anchor" href="#script-setup" aria-hidden="true">#</a> <code>&lt;script setup&gt;</code></h4><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>&lt;script lang=&quot;ts&quot; setup&gt;\nimport { useVModel } from &#39;@vueuse/core&#39;\n\nconst props = defineProps&lt;{\n  modelValue: string\n}&gt;()\nconst emit = defineEmits([&#39;update:modelValue&#39;])\n\nconst data = useVModel(props, &#39;modelValue&#39;, emit)\n&lt;/script&gt;\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="参考资料" tabindex="-1"><a class="header-anchor" href="#参考资料" aria-hidden="true">#</a> 参考资料</h2><p>https://blog.csdn.net/qq_39327418/article/details/122527337</p>',21),c={},o=(0,i(63243).Z)(c,[["render",function(e,s){const i=(0,a.up)("ExternalLinkIcon");return(0,a.wg)(),(0,a.iD)(a.HY,null,[n,(0,a._)("p",null,[d,(0,a._)("a",t,[r,(0,a.Wm)(i)]),l]),u],64)}]])},63243:(e,s)=>{s.Z=(e,s)=>{const i=e.__vccOpts||e;for(const[e,a]of s)i[e]=a;return i}}}]);